  "appendices": {
    "analysisModels": {
      "flowchartDiagram": {
        "syntaxExplanation": "Flowcharts illustrate processes and decision logic. Nodes represent steps or decisions, and arrows show the flow. `TD` (Top-Down) specifies the diagram's orientation. Node IDs are alphanumeric, and labels with spaces are enclosed in double quotes.",
        "code": "flowchart TD\n    A1[\"User Visits Site\"] --> B1[\"View Homepage\"]\n    B1 --> C1{\"Search or Browse?\"}\n    C1 -->|Search| D1[\"Enter Search Query\"]\n    C1 -->|Browse| E1[\"Select Content Section\"]\n    D1 --> F1[\"Display Search Results\"]\n    E1 --> G1[\"Display Content Page\"]\n    F1 --> H1{\"Content Relevant?\"}\n    G1 --> H1\n    H1 -->|Yes| I1[\"Engage With Content\"]\n    H1 -->|No| J1[\"Refine Search Query\"]\n    I1 --> K1([\"Decision to Explore CS Made\"])\n    J1 --> D1",
        "caption": "User Journey for Information Discovery on get real 0.2"
      },
      "sequenceDiagram": {
        "syntaxExplanation": "Sequence diagrams show interactions between participants in a temporal order. Participants are declared first, followed by messages exchanged between them. Arrows indicate message type (synchronous `->>`, asynchronous `->>`), and `+` and `-` denote activation/deactivation of lifelines. Aliases (e.g., `WI as \"Web Interface\"`) are used for clarity.",
        "code": "sequenceDiagram\n    participant User\n    participant WI as \"get real 0.2 Web Interface\"\n    participant SB as \"get real 0.2 System Backend\"\n    participant Professor\n\n    User->>WI: View \"Ask a Grad or Prof\" page\n    WI->>SB: Request current FAQ content\n    SB-->>WI: Return FAQ data\n    WI-->>User: Display FAQ and question form\n    User->>WI: Submit new question\n    WI->>+SB: Store \"Question\" (text, student_id)\n    SB->>Professor: Notify new question (email/dashboard)\n    Professor->>SB: Submit \"Answer\" (text, question_id)\n    SB-->>-WI: Update FAQ and Question status\n    WI-->>User: Display updated FAQ / confirmation",
        "caption": "Sequence for User Submitting a Question to a Professor"
      },
      "entityRelationshipDiagram": {
        "syntaxExplanation": "ER diagrams model the relationships between entities in a database. Entities are represented with attributes, which can be designated as Primary Keys (PK), Foreign Keys (FK), or Unique Keys (UK). Relationships denote how entities are connected, with cardinality symbols (`||`, `|{`, `o{`, `}|`) indicating the type of relationship (e.g., one-to-one, one-to-many). Relationship labels are enclosed in double quotes.",
        "code": "erDiagram\n    STUDENT ||--o{ QUESTION : \"submits\"\n    PROFESSIONAL ||--o{ ANSWER : \"provides\"\n    QUESTION ||--o{ ANSWER : \"receives\"\n    WEB_PAGE ||--o{ PROFESSIONAL : \"features\"\n    WEB_PAGE ||--o{ EXTERNAL_ARTICLE : \"links_to\"\n    WEB_PAGE ||--o{ ORGANIZATION : \"lists\"\n    WEB_PAGE ||--o{ CURRICULUM_RECOMMENDATION : \"presents\"\n\n    STUDENT {\n        int id PK\n        string grade_level\n        string interest_in_cs\n    }\n    WEB_PAGE {\n        int id PK\n        string title\n        string content_html\n        string page_type\n    }\n    PROFESSIONAL {\n        int id PK\n        string name\n        string title\n        string institution\n        string profile_video_url\n    }\n    QUESTION {\n        int id PK\n        int student_id FK\n        string question_text\n        string status\n        datetime submitted_at\n    }\n    ANSWER {\n        int id PK\n        int question_id FK\n        int prof_id FK\n        string answer_text\n        datetime answered_at\n    }\n    ORGANIZATION {\n        int id PK\n        string name\n        string url\n        string description\n    }\n    EXTERNAL_ARTICLE {\n        int id PK\n        string title\n        string url\n        string source_name\n        date published_date\n    }\n    CURRICULUM_RECOMMENDATION {\n        int id PK\n        string title\n        string source_url\n        string description\n    }",
        "caption": "Core Data Model for get real 0.2 Website"
      }
    },
    "tbdList": [
      "GR0-TBD-001: Need to determine the extent of community and private colleges in Oregon to be included in the 'Exploring College' section.",
      "GR0-TBD-002: Further input needed from students and high school counselors regarding related sites visited for career information (e.g., beyond Google, Yahoo, news.myspace.com, engineergirl.org).",
      "GR0-TBD-003: Prototype and prioritize the list of proposed new pages/sections.",
      "GR0-TBD-004: Review UW CS videos (http://www.cs.washington.edu/education/ugrad/prospective/download.html) as examples for 'Real People' video profiles.",
      "GR0-TBD-005: Determine the specific curricula recommendations from OUS campuses and other university sources for the 'High School Courses' section, noting that UO is currently working on this area."
    ]
  },
  "promptSettingsUsed": {
    "profile": "default",
    "depth": 5,
