  "glossary": [
    {
      "term": "Master Password",
      "definition": "The primary password or key that encrypts and decrypts the entire **keepass** database. Without it, the database is inaccessible."
    },
    {
      "term": "Key File",
      "definition": "An optional external file used in conjunction with or instead of a Master Password for database encryption and decryption."
    },
    {
      "term": "Composite Master Key",
      "definition": "A Master Key formed by combining multiple authentication factors, such as a password, a key file, and **Windows** account details, to enhance security."
    },
    {
      "term": "Entry",
      "definition": "A single record in the **keepass** database containing sensitive information like a title, username, password, URL, and notes."
    },
    {
      "term": "Group",
      "definition": "A top-level category within the **keepass** database used to organize related entries and subgroups."
    },
    {
      "term": "Subgroup",
      "definition": "A nested category within a Group, further organizing entries hierarchically."
    },
    {
      "term": "Auto-Type",
      "definition": "A feature that automates the input of credentials (username and password) into external applications or web forms by simulating keystrokes."
    },
    {
      "term": "TAN (Transaction Authentication Number)",
      "definition": "A one-time password generated for specific transactions, used to enhance security by preventing credential reuse."
    },
    {
      "term": "OSI Certified Open Source Software",
      "definition": "Software officially recognized by the Open Source Initiative as meeting specific criteria for open-source licensing and distribution."
    },
    {
      "term": "AES (Advanced Encryption Standard)",
      "definition": "A symmetric block cipher widely used for secure data encryption, implemented in **keepass** with a 256-bit key."
    },
    {
      "term": "Twofish",
      "definition": "A symmetric block cipher, similar to **AES**, also used by **keepass** for secure data encryption with a 256-bit key."
    },
    {
      "term": "SHA-256 (Secure Hash Algorithm 256-bit)",
      "definition": "A cryptographic hash function used to generate a fixed-size hash value from input data, specifically for Master Password hashing in **keepass**."
    },
    {
      "term": "ARC4 (Alleged RC4)",
      "definition": "A stream cipher used in **keepass** to encrypt passwords within the application's process memory during runtime."
    }
  ],
